\\
x^nF(x) \equiv x^{n - m}Q(x) * x^{m}G(x)\ \ (mod\ \ x^{n - m - 1})
\\
F_R(x) \equiv Q_R(x) * G_R(x)\ \ (mod\ \ x^{n - m - 1})
\\
Q_R(x) \equiv F_R(x) * G_R(x)^{-1}\ \ (mod\ \ x^{n - m - 1})
