(r - k)\dbinom{r}{k} =&amp;amp; (r - k)\dbinom{r}{r - k} \\
=&amp;amp; (r - k)\frac {r}{r - k}\dbinom{r - 1}{r - k - 1} \\
=&amp;amp; r\dbinom{r - 1}{r - k - 1} \\
=&amp;amp; r\dbinom{r - 1}{k}
\end{aligned}
